create table public.telegram_accounts (id uuid primary key default gen_random_uuid(), user_id uuid references public.profiles(id) on delete set null, business_id uuid references public.businesses(id) on delete set null, telegram_user_id bigint not null, telegram_chat_id bigint not null, username text, linked_at timestamptz, unlinked_at timestamptz, link_token_hash text, link_token_expires_at timestamptz, created_at timestamptz not null default public.current_timestamp_utc(), updated_at timestamptz not null default public.current_timestamp_utc(), unique (telegram_user_id, telegram_chat_id), check ((linked_at is null) = (business_id is null)));
create table public.telegram_conversation_states (id uuid primary key default gen_random_uuid(), telegram_account_id uuid not null references public.telegram_accounts(id) on delete cascade, draft jsonb not null check (jsonb_typeof(draft) = 'object'), mode text not null check (mode in ('awaiting_clarification','awaiting_correction','awaiting_review','awaiting_replacement')), requested_field text, inline_message_id bigint, expires_at timestamptz not null, created_at timestamptz not null default public.current_timestamp_utc(), updated_at timestamptz not null default public.current_timestamp_utc(), unique (telegram_account_id));
create table public.telegram_user_preferences (telegram_account_id uuid primary key references public.telegram_accounts(id) on delete cascade, language text not null default 'en' check (language in ('en','ms')), timezone text not null default 'Asia/Kuala_Lumpur', preferences jsonb not null default '{}'::jsonb check (jsonb_typeof(preferences) = 'object'), created_at timestamptz not null default public.current_timestamp_utc(), updated_at timestamptz not null default public.current_timestamp_utc());
create trigger telegram_accounts_set_updated_at before update on public.telegram_accounts for each row execute function public.set_updated_at(); create trigger telegram_conversation_states_set_updated_at before update on public.telegram_conversation_states for each row execute function public.set_updated_at(); create trigger telegram_user_preferences_set_updated_at before update on public.telegram_user_preferences for each row execute function public.set_updated_at();
create index telegram_accounts_business_idx on public.telegram_accounts (business_id) where unlinked_at is null; create index telegram_conversation_states_expiry_idx on public.telegram_conversation_states (expires_at);
